1	/**
2	 * P0/P1客户全量深抓 — 点击每个P0/P1客户，加载全部聊天记录，提取完整消息
3	 * 用法: node deep-scrape-p0p1.mjs
4	 * 前置: Chrome 9222已开，小满TM页面已登录
5	 */
6	
7	import { chromium } from 'playwright';
8	import { writeFileSync, mkdirSync, existsSync, readFileSync } from 'fs';
9	import { join, dirname } from 'path';
10	import { fileURLToPath } from 'url';
11	
12	const __dirname = dirname(fileURLToPath(import.meta.url));
13	const DATA_DIR = join(__dirname, '..', 'data');
14	const CDP_URL = 'http://127.0.0.1:9222';
15	
16	if (!existsSync(DATA_DIR)) mkdirSync(DATA_DIR, { recursive: true });
17	
18	async function connect() {
19	  const browser = await chromium.connectOverCDP(CDP_URL);
20	  const ctx = browser.contexts()[0];
21	  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
22	  if (!page) throw new Error('未找到小满页面');
23	  const talkFrame = page.frames()[1];
24	  if (!talkFrame) throw new Error('未找到聊天 iframe');
25	  return { browser, ctx, page, talkFrame };
26	}
27	
28	async function getConversationList(frame) {
29	  return frame.evaluate(() => {
30	    return Array.from(document.querySelectorAll('.contact-item-container')).map((el, idx) => {
31	      const nameEl = el.querySelector('.contact-right');
32	      const nameText = nameEl ? (nameEl.textContent || '').trim() : '';
33	      const nameMatch = nameText.match(/^(.+?)(?:\d{2,4}[-:\/])/);
34	      const name = nameMatch ? nameMatch[1].trim() : nameText.substring(0, 30).trim() || 'unknown';
35	      return { index: idx, name };
36	    });
37	  });
38	}
39	
40	async function clickConversation(frame, index) {
41	  await frame.evaluate((idx) => {
42	    const containers = document.querySelectorAll('.contact-item-container');
43	    const target = containers[idx];
44	    if (target) {
45	      target.scrollIntoView({ block: 'center' });
46	      target.click();
47	    }
48	  }, index);
49	  // Dynamic wait: poll until conversation header updates
50	  // No more fixed 1500ms timeout — the root cause of DOM串位
51	  for (let i = 0; i < 20; i++) {
52	    await new Promise(r => setTimeout(r, 300));
53	    const loaded = await frame.evaluate(() => {
54	      const header = document.querySelector('.im-header-title, .session-header-title, .chat-header-title');
55	      return header ? (header.textContent || '').trim() : '';
56	    });
57	    if (loaded.length > 0) break;
58	  }
59	}
60	
61	// ============================================================
62	// Identity verification — prevent DOM串位
63	// After clicking a customer, verify the loaded conversation
64	// actually belongs to them before reading messages.
65	// ============================================================
66	async function verifyConversationIdentity(frame, expectedName) {
67	  for (let attempt = 0; attempt < 10; attempt++) {
68	    const actualName = await frame.evaluate(() => {
69	      const header = document.querySelector('.im-header-title, .session-header-title, .chat-header-title');
70	      if (header) return (header.textContent || '').trim();
71	      // Fallback: check sidebar selection
72	      const selected = document.querySelector('.contact-item-container.selected .contact-right');
73	      if (selected) return (selected.textContent || '').trim().substring(0, 30);
74	      return '';
75	    });
76	
77	    // Fuzzy match: the header may contain extra info (company, country)
78	    if (actualName && (
79	      actualName.includes(expectedName) ||
80	      expectedName.includes(actualName) ||
81	      actualName.toLowerCase() === expectedName.toLowerCase()
82	    )) {
83	      return true;
84	    }
85	
86	    // If no name detected yet, wait and retry
87	    if (!actualName || actualName.length === 0) {
88	      await new Promise(r => setTimeout(r, 500));
89	      continue;
90	    }
91	
92	    // Name mismatch! Previous conversation still showing.
93	    // Wait longer for iframe to actually switch.
94	    console.log(` [⏳等待切换: 期望${expectedName}, 实际${actualName}]`);
95	    await new Promise(r => setTimeout(r, 800));
96	  }
97	
98	  return false;
99	}
100	
101	async function waitForMessages(frame, targetName) {
102	  for (let i = 0; i < 15; i++) {
103	    const hasContent = await frame.evaluate(() =>
104	      document.querySelectorAll('.session-rich-content.text, .session-rich-content.card').length > 0
105	    );
106	    if (hasContent) {
107	      // Verify identity before returning
108	      if (targetName) {
109	        const verified = await verifyConversationIdentity(frame, targetName);
110	        if (verified) return true;
111	        // Not verified — keep waiting
112	        await new Promise(r => setTimeout(r, 500));
113	        continue;
114	      }
115	      return true;
116	    }
117	    await new Promise(r => setTimeout(r, 500));
118	  }
119	  return false;
120	}
121	
122	async function scrollChatToLoadAll(frame, { maxScrolls = 40, stableThreshold = 3 } = {}) {
123	  const containerInfo = await frame.evaluate(() => {
124	    const selectors = [
125	      '.message-list-container', '.chat-list', '.im-chat-list',
126	      '.message-list', '[class*="message-list"]', '[class*="chat-list"]',
127	      '[class*="chat-content"]', '.session-message-list-wrapper',
128	    ];
129	    for (const sel of selectors) {
130	      const el = document.querySelector(sel);
131	      if (el && el.scrollHeight > el.clientHeight) {
132	        return { selector: sel, scrollHeight: el.scrollHeight, clientHeight: el.clientHeight };
133	      }
134	    }
135	    return null;
136	  });
137	
138	  if (!containerInfo) return 0;
139	
140	  let prevCount = 0;
141	  let stableCount = 0;
142	  let totalScrolled = 0;
143	
144	  for (let i = 0; i < maxScrolls; i++) {
145	    const { count, scrolled } = await frame.evaluate((sel) => {
146	      const container = document.querySelector(sel);
147	      if (!container) return { count: 0, scrolled: false };
148	      const old = container.scrollTop;
149	      container.scrollTop = 0;
150	      return {
151	        count: document.querySelectorAll('.message-item-wrapper.messenger').length,
152	        scrolled: old > 0,
153	      };
154	    }, containerInfo.selector);
155	
156	    totalScrolled++;
157	    if (scrolled) await new Promise(r => setTimeout(r, 600));
158	
159	    const newCount = await frame.evaluate(() =>
160	      document.querySelectorAll('.message-item-wrapper.messenger').length
161	    );
162	
163	    if (newCount === prevCount) {
164	      stableCount++;
165	      if (stableCount >= stableThreshold) break;
166	    } else {
167	      stableCount = 0;
168	    }
169	    prevCount = newCount;
170	    if (!scrolled) break;
171	  }
172	
173	  return prevCount;
174	}
175	
176	async function getRenderedMessages(frame) {
177	  return frame.evaluate(() => {
178	    const messages = [];
179	    document.querySelectorAll('.message-item-wrapper.messenger').forEach(wrapper => {
180	      const isLeft = wrapper.classList.contains('item-left');
181	      const isRight = wrapper.classList.contains('item-right');
182	      const securityEl = wrapper.querySelector('.session-security');
183	      if (securityEl) return;
184	
185	      const textEl = wrapper.querySelector('.session-rich-content.text');
186	      const cardEl = wrapper.querySelector('.session-rich-content.card');
187	
188	      let content = '';
189	      let isCard = false;
190	      let cardData = null;
191	
192	      if (textEl) {
193	        content = textEl.textContent.trim()
194	          .replace(/翻译中…反馈$/, '')
195	          .replace(/由阿里翻译提供反馈$/, '')
196	          .replace(/阿里国际Marco大模型翻译反馈$/, '')
197	          .replace(/由阿里翻译提供$/, '')
198	          .trim();
199	      } else if (cardEl) {
200	        content = cardEl.textContent.trim();
201	        isCard = true;
202	        const expinfo = cardEl.getAttribute('data-expinfo');
203	        if (expinfo) {
204	          try { cardData = JSON.parse(expinfo); } catch (e) {}
205	        }
206	      } else {
207	        return;
208	      }
209	
210	      const timeEl = wrapper.querySelector('p.item-base-info span:last-child');
211	      const timestamp = timeEl ? (timeEl.textContent || '').trim() : null;
212	
213	      const contentImgs = wrapper.querySelectorAll('img');
214	      const hasImages = Array.from(contentImgs).some(img => {
215	        if (img.classList.contains('emotion')) return false;
216	        const s = img.src || '';
217	        if (!s.startsWith('http')) return false;
218	        if (s.includes('atmgateway-client.alibaba.com/smily')) return false;
219	        if (s.includes('clouddisk.alibaba.com')) return false;
220	        return true;
221	      });
222	
223	      messages.push({
224	        side: isLeft ? 'received' : isRight ? 'sent' : 'system',
