1	/**
2	 * 小满CRM — 快照对比引擎
3	 *
4	 * 对比两次索引快照，识别状态变化并生成P0/P1/P2优先级清单。
5	 * 可独立运行，也可被scheduler调用。
6	 *
7	 * 用法: node diff.mjs [昨天快照路径] [今天快照路径]
8	 *       node diff.mjs  (自动找最近两次快照对比)
9	 */
10	
11	import { readFileSync, readdirSync, writeFileSync, existsSync, mkdirSync } from 'fs';
12	import { join, dirname } from 'path';
13	import { fileURLToPath } from 'url';
14	
15	const __dirname = dirname(fileURLToPath(import.meta.url));
16	const DATA_DIR = join(__dirname, '..', 'data');
17	const SNAPSHOT_DIR = join(DATA_DIR, 'snapshots');
18	const DIFF_DIR = join(DATA_DIR, 'diffs');
19	
20	if (!existsSync(DIFF_DIR)) mkdirSync(DIFF_DIR, { recursive: true });
21	
22	// ============================================================
23	// P0-P3 分类规则引擎
24	// ============================================================
25	const P0_KEYWORDS = ['how much', 'price', 'quote', 'cost', '多少钱', 'كم', 'prix', 'precio',
26	  'complaint', 'refund', 'return', 'damage', 'defect', 'quality', 'problem'];
27	
28	function classifyCustomer(customer, prevCustomer) {
29	  const { name, isUnread, lastMessageSnippet, lastMsgDirection, lastTime } = customer;
30	
31	  // 售后关键词
32	  const msg = lastMessageSnippet.toLowerCase();
33	  const hasAfterSales = ['complaint', 'refund', 'return', 'damage', 'defect', 'quality issue', 'problem with']
34	    .some(k => msg.includes(k));
35	
36	  // 报价/价格关键词
37	  const hasPriceKeywords = P0_KEYWORDS.some(k => msg.includes(k));
38	
39	  // 判断消息方向（如果无法从DOM判断，用启发式）
40	  const isFromClient = lastMsgDirection === 'received' ||
41	    (!lastMessageSnippet.startsWith('我') &&
42	     !lastMessageSnippet.includes('发送了') &&
43	     !lastMessageSnippet.includes('以上内容'));
44	
45	  // ==================== P0: 紧急 ====================
46	  if (hasAfterSales) {
47	    return { priority: 'P0', categoryId: 'after_sales', tier: 'S', reason: '售后投诉/质量问题' };
48	  }
49	
50	  // 客户最后发言 + 未读 → 我方未回复
51	  if (isFromClient && isUnread) {
52	    if (hasPriceKeywords) {
53	      return { priority: 'P0', categoryId: 'awaiting_reply', tier: 'S', reason: '客户询价/砍价未回复' };
54	    }
55	    return { priority: 'P0', categoryId: 'awaiting_reply', tier: 'A', reason: '客户消息未回复' };
56	  }
57	
58	  // 我方最后发言 + 未读 → 客户已读不回
59	  if (!isFromClient && isUnread) {
60	    if (hasPriceKeywords) {
61	      return { priority: 'P0', categoryId: 'awaiting_reply', tier: 'A', reason: '报价后客户已读未回' };
62	    }
63	    return { priority: 'P0', categoryId: 'awaiting_reply', tier: 'B', reason: '我方消息客户已读未回' };
64	  }
65	
66	  // 全部已读 + 客户最后发言 → 待报价/谈判中
67	  if (isFromClient && !isUnread) {
68	    if (hasPriceKeywords) {
69	      return { priority: 'P0', categoryId: 'negotiating', tier: 'A', reason: '价格谈判中' };
70	    }
71	    return { priority: 'P1', categoryId: 'awaiting_quote', tier: 'B', reason: '待分析客户需求' };
72	  }
73	
74	  // ==================== P1: 高优 ====================
75	  if (msg.includes('sample') || msg.includes('test order')) {
76	    return { priority: 'P1', categoryId: 'sample_request', tier: 'A', reason: '样品相关' };
77	  }
78	  if (msg.includes('payment') || msg.includes('deposit') || msg.includes('wire')) {
79	    return { priority: 'P1', categoryId: 'awaiting_payment', tier: 'A', reason: '待付款' };
80	  }
81	  if (msg.includes('ship') || msg.includes('delivery') || msg.includes('tracking')) {
82	    return { priority: 'P1', categoryId: 'awaiting_delivery', tier: 'A', reason: '物流/发货相关' };
83	  }
84	
85	  // ==================== P2: 待回访 ====================
86	  // 如果和上次快照比，lastTime相同（没新消息）且超过7天
87	  // 这里不做时间判断，留给上层逻辑
88	
89	  // ==================== P3: 低优 ====================
90	  return { priority: 'P3', categoryId: 'keep_warm', tier: 'C', reason: '常规维护' };
91	
92	  // 注意：P2 followup 和 P3 activate 的判断需要历史数据，在 compare() 中处理
93	}
94	
95	// ============================================================
96	// 快照对比
97	// ============================================================
98	function compare(prevSnapshot, currSnapshot) {
99	  const prevMap = new Map(prevSnapshot.customers.map(c => [c.name, c]));
100	  const currMap = new Map(currSnapshot.customers.map(c => [c.name, c]));
101	
102	  const newCustomers = [];
103	  const changed = [];
104	  const urgency = { P0: [], P1: [], P2: [], P3: [] };
105	
106	  for (const [name, curr] of currMap) {
107	    const prev = prevMap.get(name);
108	
109	    // 新客户
110	    if (!prev) {
111	      const cls = classifyCustomer(curr, null);
112	      newCustomers.push({ name, ...curr, classification: cls });
113	      if (cls.priority === 'P0') urgency.P0.push({ name, ...curr, classification: cls });
114	      else if (cls.priority === 'P1') urgency.P1.push({ name, ...curr, classification: cls });
115	      else urgency.P3.push({ name, ...curr, classification: { ...cls, categoryId: 'activate', reason: '新线索待激活' } });
116	      continue;
117	    }
118	
119	    // 状态变化检测
120	    const statusChanged = curr.isUnread !== prev.isUnread;
121	    const messageChanged = curr.lastMessageSnippet !== prev.lastMessageSnippet;
122	    const timeChanged = curr.lastTime !== prev.lastTime;
123	
124	    if (statusChanged || messageChanged || timeChanged) {
125	      const cls = classifyCustomer(curr, prev);
126	      changed.push({
127	        name,
128	        ...curr,
129	        prevState: { isUnread: prev.isUnread, lastMessage: prev.lastMessageSnippet, lastTime: prev.lastTime },
130	        currState: { isUnread: curr.isUnread, lastMessage: curr.lastMessageSnippet, lastTime: curr.lastTime },
131	        changeType: statusChanged ? (curr.isUnread ? '变为未读' : '已读') : '消息更新',
132	        classification: cls
133	      });
134	
135	      if (urgency[cls.priority]) {
136	        urgency[cls.priority].push({ name, ...curr, classification: cls });
137	      }
138	    }
139	  }
140	
141	  // 检查消失的客户（可能被删除/归档）
142	  const removed = [];
143	  for (const [name, prev] of prevMap) {
144	    if (!currMap.has(name)) {
145	      removed.push({ name, lastState: prev });
146	    }
147	  }
148	
149	  return {
150	    comparedAt: new Date().toISOString(),
151	    prevSnapshot: { file: prevSnapshot._file, capturedAt: prevSnapshot.capturedAt, total: prevSnapshot.totalCustomers },
152	    currSnapshot: { file: currSnapshot._file, capturedAt: currSnapshot.capturedAt, total: currSnapshot.totalCustomers },
153	    summary: {
154	      newCustomers: newCustomers.length,
155	      changed: changed.length,
156	      removed: removed.length,
157	      unchanged: currSnapshot.totalCustomers - newCustomers.length - changed.length,
158	      P0: urgency.P0.length,
159	      P1: urgency.P1.length,
160	      P2: urgency.P2.length,
161	      P3: urgency.P3.length
162	    },
163	    urgency,
164	    changed,
165	    newCustomers: newCustomers.slice(0, 20), // 新客户太多的话只保留前20
166	    removed
167	  };
168	}
