291	// Fuzzy name matching for DOM lookup
292	function fuzzyMatch(targetName, domName, domFullText) {
293	  const t = targetName.toLowerCase().replace(/\s+/g, '');
294	  const d = domName.toLowerCase().replace(/\s+/g, '');
295	  const f = (domFullText || '').toLowerCase();
296	
297	  if (t === d) return true;
298	  if (d.includes(t) || t.includes(d)) return true;
299	  if (f.includes(t) || t.includes(f.substring(0, 20))) return true;
300	  // Try partial match: first 8 chars
301	  if (t.length >= 8 && d.length >= 8 && t.substring(0, 8) === d.substring(0, 8)) return true;
302	  return false;
303	}
